	AccessDeniedException_message = AccessDeniedException.AddMember("message", _ErrorMessage)

	UserIdentity_id = UserIdentity.AddMember("id", _IdentityId)

	GroupIdentity_id = GroupIdentity.AddMember("id", _IdentityId)

